// Parsea el JSON que devuelve el modelo, tolerando markdown accidental y errores
const content = ($json && $json.choices && $json.choices[0] && $json.choices[0].message && $json.choices[0].message.content) || '';
let parsed = {};
try {
  parsed = JSON.parse(content);
} catch (e) {
  try {
    const clean = content.replace(/```json/gi, '').replace(/```/g, '').trim();
    parsed = JSON.parse(clean);
  } catch (err) {
    throw new Error("No se pudo parsear la respuesta del modelo de IA a JSON válido: " + content);
  }
}

// Validación y Sanitización estricta
let tipo = (parsed.tipo || 'venta').toString().toLowerCase().trim();
if (!['venta', 'ingreso', 'gasto', 'traslado'].includes(tipo)) {
  tipo = 'venta';
}

let cantidad = Math.round(Number(parsed.cantidad || 0));
if (isNaN(cantidad) || cantidad <= 0) {
  cantidad = 1;
}

let precio_unitario = parsed.precio_unitario === null || parsed.precio_unitario === undefined
  ? null
  : Math.abs(Number(parsed.precio_unitario));
if (isNaN(precio_unitario)) {
  precio_unitario = null;
}

let producto = (parsed.producto || 'Producto Genérico').toString().trim();
// Escapar comillas simples para seguridad SQL
producto = producto.replace(/'/g, "''");

let categoria_ruta = parsed.categoria_ruta ? String(parsed.categoria_ruta).toLowerCase().trim() : null;
const categorias_validas = ['tubos_conexiones', 'griferia_valvulas', 'herramientas_accesorios', 'repuestos_empaques', 'otros'];
if (categoria_ruta && !categorias_validas.includes(categoria_ruta)) {
  categoria_ruta = null;
}

return [{
  json: {
    tipo,
    producto,
    cantidad,
    precio_unitario,
    categoria_ruta
  }
}];

// Procesa callback_data: "deshacer:<movimiento_id>:<authorized_user_id>"
const data = ($json.callback_query?.data || '').toString();
const [action, movimiento_id, authorized_user_id] = data.split(':');
return [{
  json: {
    action,
    movimiento_id: Number(movimiento_id),
    authorized_user_id: Number(authorized_user_id),
    clicker_telegram_id: Number($json.callback_query?.from?.id),
    chat_id: $json.callback_query?.message?.chat?.id,
    message_id: $json.callback_query?.message?.message_id
  }
}];

const movimiento = $json;
const clicker_telegram_id = Number($node["Parse Callback Data"].json.clicker_telegram_id);

if (!movimiento || !movimiento.created_at) {
  return [{
    json: {
      valid: false,
      reason: "⚠️ El registro ya no existe o ya fue revertido anteriormente."
    }
  }];
}

const created_at = new Date(movimiento.created_at);
const now = new Date();
const diffMinutes = (now - created_at) / 1000 / 60;

if (diffMinutes > 5) {
  return [{
    json: {
      valid: false,
      reason: "⚠️ Tiempo límite excedido (máx 5 minutos). No es posible revertir esta operación."
    }
  }];
}

if (clicker_telegram_id !== Number(movimiento.creador_telegram_id)) {
  return [{
    json: {
      valid: false,
      reason: "⚠️ No autorizado. Solo el operario que registró esta venta original puede revertirla."
    }
  }];
}

return [{
  json: {
    valid: true,
    movimiento_id: $node["Parse Callback Data"].json.movimiento_id
  }
}];
